import sys
from collections import defaultdict, deque

def main():
    sys.setrecursionlimit(10000)
    N, M = map(int, sys.stdin.readline().split())
    edges = [[] for _ in range(N + 1)]
    for _ in range(M):
        a, b = map(int, sys.stdin.readline().split())
        edges[a].append(b)

    # Build the adjacency list for the graph
    graph = [[] for _ in range(N + 1)]
    for a in range(1, N + 1):
        for b in edges[a]:
            graph[a].append(b)

    # Perform topological sort to find the node with in-degree 0
    in_degree = [0] * (N + 1)
    for a in range(1, N + 1):
        for b in edges[a]:
            in_degree[b] += 1

    queue = deque()
    for i in range(1, N + 1):
        if in_degree[i] == 0:
            queue.append(i)

    # If there is more than one node with in-degree 0, then there are multiple possible strongest programmers
    if len(queue) > 1:
        print(-1)
        return

    # If there is exactly one node with in-degree 0, it is the strongest
    print(queue[0])

if __name__ == "__main__":
    main()
